 82	    {
 83	        // Arrange
 84	        await using var scope = _fixture.Factory.Services.CreateAsyncScope();
 85	        var dbContext = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
 86	        var firstUser = CreateUser("first-owner@example.test", "First owner");
 87	        var secondUser = CreateUser("second-owner@example.test", "Second owner");
 88	        var firstWorkspace = new Workspace(Guid.NewGuid(), "First workspace", DateTimeOffset.UtcNow);
 89	        var secondWorkspace = new Workspace(Guid.NewGuid(), "Second workspace", DateTimeOffset.UtcNow);
 90	        dbContext.AddRange(firstUser, secondUser, firstWorkspace, secondWorkspace);
 91	        dbContext.AddRange(
 92	            new WorkspaceMember(Guid.NewGuid(), firstWorkspace.Id, firstUser.Id, WorkspaceMemberRole.Owner, DateTimeOffset.UtcNow),
 93	            new WorkspaceMember(Guid.NewGuid(), secondWorkspace.Id, secondUser.Id, WorkspaceMemberRole.Owner, DateTimeOffset.UtcNow));
 94	        await dbContext.SaveChangesAsync();
 95	
 96	        var resolver = CreateResolver(dbContext, firstUser.Id);
 97	
 98	        // Act
 99	        var currentWorkspace = await resolver.GetAsync();
100	
101	        // Assert
102	        Assert.NotNull(currentWorkspace);
103	        Assert.Equal(firstWorkspace.Id, currentWorkspace.Id);
104	        Assert.NotEqual(secondWorkspace.Id, currentWorkspace.Id);
105	
106	        // Arrange
107	        var additionalWorkspace = new Workspace(Guid.NewGuid(), "Additional workspace", DateTimeOffset.UtcNow);
108	        dbContext.Workspaces.Add(additionalWorkspace);
109	        dbContext.WorkspaceMembers.Add(new WorkspaceMember(
110	            Guid.NewGuid(),
111	            additionalWorkspace.Id,
112	            firstUser.Id,
113	            WorkspaceMemberRole.Owner,
114	            DateTimeOffset.UtcNow));
115	        await dbContext.SaveChangesAsync();
116	
117	        // Act
118	        var ambiguousWorkspace = await resolver.GetAsync();
119	
120	        // Assert
121	        Assert.Null(ambiguousWorkspace);
122	    }
